var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"챔피언, 지하 통로에서 상대측과 교전 중.","JPN":"チャンピオン、地下通路で相手と交戦中。","ENG":"Champion, engaging with the enemy team in the underground passage.","TWN":"冠軍，目前正在地下道和對方交手中。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"이쪽에서 확인한 적은 쇠사슬을 쓰는 카운터와 도폭선을 쓰는 카운터, 둘뿐이다.","JPN":"こちらで確認した敵は鉄の鎖を使うカウンターと、導爆戦を使うカウンター、二人のみだ。","ENG":"We have identified the two individuals. Both Counters. One who uses chains, and the other who uses detonation cords.","TWN":"確認到的敵人有，使用鐵鍊的制裁者和用導火線的制裁者，二個而已。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"다른 적은 확인되지 않는다. 아마도 다른 루트를 이용하는 것 같다.","JPN":"他の敵は確認できない。おそらく別ルートに行くと思われる。","ENG":"Unable to confirm visual on other enemies. They are probably using another route.","TWN":"沒看到其他敵人，可能在其他路線。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야, 설마 양동 작전으로 오는 거야? 없는 인원으로 열심히네.","JPN":"何よ、まさか陽動作戦？　人数も少ないのに頑張るわね。","ENG":"What? Trying to break through using a feint operation? Aren't they stretching their resources thin.","TWN":"什麼嘛，不會是聲東擊西吧？才幾個人而已還這麼拼命。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"항공 루트는 우리한테 맡기고 계속 지하 루트를 막아줘.","JPN":"航空ルートは私たちに任せて、引き続き地下ルートをお願いね。","ENG":"Leave the aerial route to us and keep blocking off the underground route.","TWN":"空中路線就交給我們，地下路線你們繼續守著。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"신호를 줄 때까지 제압하지는 말고. 천천히 몰아가.","JPN":"合図するまで制圧はしないで、ゆっくり追い詰めていって。","ENG":"Don't subdue them until I give you the signal. Corner them slowly.","TWN":"在我發出訊號前不要出手制服他們，而是要慢慢逼近。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"알았다.","JPN":"了解。","ENG":"Understood.","TWN":"知道了。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자, 그럼 애들아! 우리도 슬슬 손님 맞을 준비를 해볼까?","JPN":"さて、みんな！　そろそろ私たちもお客様を迎える準備をしようかな？","ENG":"Okay, guys! We should start preparing to greet our guests!","TWN":"來吧，大家！差不多要準備迎接客人囉？"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다들 수송기가 나타났다고 바로 공격하지 말고 뜸들인 후에 천천히 공격해.","JPN":"輸送船が現れたらすぐには攻撃せず、一呼吸置いてからゆっくり攻撃して。","ENG":"But don't start shooting at the aircraft as soon as you see it. Give it some time and attack slowly.","TWN":"不要看到運輸機就馬上攻擊，先停一下之後再慢慢攻擊。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"거점에 발을 들이기는 쉬워도. 함부로 뺄 수는 없게끔 말이야.","JPN":"わざと拠点に足を踏み入れさせて、簡単には逃げ出せなくさせるためよ。","ENG":"Make it so that it's easy coming into our base, but not so much trying to leave it.","TWN":"讓他們可以輕易進來，卻走不出去。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"오지만디아스님, 그럼 거점은 누가 지킬까요?","JPN":"オジマンディアス様、それでは拠点は誰が守るんでしょうか？","ENG":"Miss Ozymandias, then who will guard the base?","TWN":"奧茲曼迪亞斯，那誰負責把守據點？"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"지킨다고? 시시하게 무슨 소리를 하는 거야?","JPN":"守る？　何つまらないことを言っているのよ。","ENG":"Guard? What kind of boring nonsense is that?","TWN":"把守？你在說什麼？"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"거점은 나 혼자만으로도 충분해. 녀석들은 날 만나러 오는 거거든.","JPN":"拠点は私一人で十分。あいつらは私に用があるんだもの。","ENG":"I'll be fine alone at the base. They are here to see me, after all.","TWN":"據點交給我一個人把守就好，那些傢伙就是衝著我來的。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그러니까 환영해줘야지. 그 다음엔 전부 리타이어 시켜버릴 거지만.","JPN":"だったら歓迎してあげなくちゃ。その後は全員リタイアさせちゃうけどね。","ENG":"So, I'll have to welcome them. Even if I'm going to crush them soon after.","TWN":"我當然要歡迎他們，再把他們全都淘汰。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};